let API=(()=>{var e;return window.FILA_API_URL?window.FILA_API_URL.replace(/\/$/,""):"localhost"===(e=window.location.hostname)||"127.0.0.1"===e?"http://localhost:3000":"file:"===window.location.protocol?"https://fila-treinamento.onrender.com":window.location.origin})();function escapeHTML(e){return String(e??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#039;")}async function requestJSON(e){e=await fetch(""+API+e);if(e.ok)return e.json();throw new Error("Erro ao carregar painel.")}function corPorTipo(e=""){return e.includes("2°")||e.includes("2º")?"#2563eb":e.includes("3°")||e.includes("3º")?"#ea580c":e.includes("Dúvida")||e.includes("Dúvidas")?"#7c3aed":"#16a34a"}function renderFila(e){return e.length?e.map((e,n)=>`<li><strong>${n+1}º</strong><span>${escapeHTML(e.nome)}</span></li>`).join(""):'<li class="tv-empty">Sem itens na fila</li>'}async function atualizarTV(){try{var e=await requestJSON("/dashboard"),{fila:n=[],filaManut:t=[],atendimentos:a=[],ranking:r=[]}=e,o=document.getElementById("tv-atual");o&&(o.innerHTML=a.length?a.map(e=>{var n=e.tipo||"Treinamento";return`
                <div class="tv-atendimento-card" style="border-left-color: ${corPorTipo(n)}">
                  <div class="tv-atendimento-titulo">
                    <h3>${escapeHTML(e.pessoa)}</h3>
                    <p>${escapeHTML(e.cliente||"-")}</p>
                    <span>${escapeHTML(n)}</span>
                  </div>
                </div>
              `}).join(""):'<p class="tv-sem-atendimento">Nenhum atendimento em andamento</p>'),document.getElementById("tv-fila-treinamento").innerHTML=renderFila(n),document.getElementById("tv-fila-manutencao").innerHTML=renderFila(t),document.getElementById("tv-ranking").innerHTML=r.length?r.map((e,n)=>`
              <tr>
                <td><strong>${n+1}</strong> ${escapeHTML(e.pessoa)}</td>
                <td>${escapeHTML(e.total)}</td>
              </tr>
            `).join(""):'<tr><td colspan="2">Sem ranking</td></tr>'}catch(e){console.error(e),document.getElementById("tv-atual").innerHTML='<p class="tv-sem-atendimento">Falha ao carregar painel</p>'}}setInterval(atualizarTV,3e4),atualizarTV();